function blogURLforModalID(modalID) {
  console.log(modalID.indexOf('global'));
  if (modalID.indexOf('global') >= 0) {
    //dont change global IDs
    return window.location;
  } else {
    modalID = modalID.replace('modal-', '');
    var siteURL = location.protocol + '//' + location.host + "/blog.html";
    siteURL += "?slug=" + modalID;
    // console.log('id= ',modalID);
    return siteURL;
  }
}

function modalShow(div) {
  document.body.style.overflow = 'hidden';
  document.body.style.height = '100vh';
  console.log("MODAL opened - ", div.id);
  //set the url for this
  window.history.replaceState({}, '', blogURLforModalID(div.id));
}

function modalClosed(div) {
  document.body.style.overflow = 'auto';
  document.body.style.height = 'auto';
  console.log("MODAL CLOSED - ", div.id);
  var path = window.location.href.split("?")[0];
  window.history.replaceState({}, '', path);
  //window.location = window.urlForModalID(modalID)
}

